mapper.select:
SELECT sn.note_id AS noteId, sn.player_id AS playerId, p.name AS playerName, t.team_name AS teamName, sn.content AS content, sn.potential_rating AS potentialRating, sn.note_date AS noteDate FROM ScoutNote sn JOIN Player p ON p.player_id = sn.player_id LEFT JOIN ActivePlayer ap ON ap.player_id = p.player_id LEFT JOIN Team t ON t.team_id = ap.current_team_id
AND p.name LIKE CONCAT('%', #{playerName}, '%')
AND sn.potential_rating >= #{minRating}
AND sn.potential_rating <= #{maxRating}
AND sn.content LIKE CONCAT('%', #{keyword}, '%')
ORDER BY sn.note_date DESC, sn.note_id DESC LIMIT #{limit} OFFSET #{offset}

mapper.update:
UPDATE ScoutNote
SET content = #{content},
    potential_rating = #{potentialRating},
    note_date = #{noteDate}
WHERE note_id = #{noteId}
